    bool is_inf = (f16_exp == 0x1F) && (f16_mant == 0);
    bool is_zero = (f16_exp == 0) && (f16_mant == 0);
    bool is_denorm = (f16_exp == 0) && (f16_mant != 0);
    bool is_normal = (f16_exp >= 1) && (f16_exp <= 30);
